// Admin Dashboard JavaScript

// HTML escaping function to prevent XSS
function escapeHTML(str) {
    if (!str) return '';
    return String(str).replace(/[&<>'"]/g, tag => ({
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        "'": '&#39;',
        '"': '&quot;'
    }[tag] || tag));
}

class AdminDashboard {
    constructor() {
        this.isAuthenticated = false;
        this.dashboardData = null;
        this.charts = {};
        this.refreshInterval = null;

        // Initialize the dashboard
        this.init();
    }

    async init() {
        // Check if already authenticated
        await this.checkAuthStatus();

        if (this.isAuthenticated) {
            this.showDashboard();
        } else {
            this.showLogin();
        }

        this.setupEventListeners();
    }

    async checkAuthStatus() {
        try {
            const response = await fetch('/.netlify/functions/get-dashboard-data');
            if (response.status === 200) {
                this.isAuthenticated = true;
                return true;
            }
        } catch (error) {
            console.log('Not authenticated');
        }
        this.isAuthenticated = false;
        return false;
    }

    setupEventListeners() {
        // Login form
        const loginForm = document.getElementById('login-form');
        if (loginForm) {
            loginForm.addEventListener('submit', (e) => this.handleLogin(e));
        }

        // Logout button
        const logoutBtn = document.getElementById('logout-btn');
        if (logoutBtn) {
            logoutBtn.addEventListener('click', () => this.handleLogout());
        }

        // Test email button
        const testEmailBtn = document.getElementById('test-email-btn');
        if (testEmailBtn) {
            testEmailBtn.addEventListener('click', () => this.handleTestEmail());
        }

        // Tab navigation
        document.querySelectorAll('.nav-tab').forEach(tab => {
            tab.addEventListener('click', (e) => this.switchTab(e.target.dataset.tab));
        });

        // Artwork sorting buttons
        document.querySelectorAll('[data-sort]').forEach(btn => {
            btn.addEventListener('click', (e) => this.sortArtworks(e.target.dataset.sort));
