#!/usr/bin/env node

/**
 * Dashboard Launcher
 * Starts the local artwork management dashboard
 */

import { spawn } from 'child_process';
import { fileURLToPath } from 'url';
import path from 'path';
import open from 'open';
import chalk from 'chalk';
import boxen from 'boxen';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

console.log(boxen(
    chalk.bold.yellow('Edmund Dantes Studio\n') +
    chalk.white('Portfolio Management Dashboard'),
    {
        padding: 1,
        margin: 1,
        borderStyle: 'round',
        borderColor: 'yellow'
    }
));

console.log(chalk.blue('\n🚀 Starting dashboard server...\n'));

// Start the backend server
const backendPath = path.join(__dirname, 'artwork-manager-backend.js');
const serverProcess = spawn('node', [backendPath], {
    stdio: 'pipe',
    env: { ...process.env, NODE_ENV: 'development' }
});

let serverStarted = false;

// Handle server output
serverProcess.stdout.on('data', (data) => {
    const output = data.toString();

    // Check if server started successfully
    if (output.includes('Server running') || output.includes('port 3001')) {
        if (!serverStarted) {
            serverStarted = true;
            console.log(chalk.green('✓ Server started successfully'));
            console.log(chalk.cyan(`\n📊 Dashboard available at: http://localhost:3001/dashboard.html\n`));

            // Open browser after a short delay
            setTimeout(() => {
                console.log(chalk.yellow('🌐 Opening dashboard in browser...\n'));
                open('http://localhost:3001/dashboard.html');
            }, 1000);
        }
    }

    // Log other server output
    if (output.trim()) {
        console.log(chalk.gray(`[Server] ${output.trim()}`));
    }
});

serverProcess.stderr.on('data', (data) => {
    console.error(chalk.red(`[Error] ${data}`));
});

// Handle server errors
serverProcess.on('error', (error) => {
    console.error(chalk.red(`\n❌ Failed to start server: ${error.message}`));
    process.exit(1);
});

// Handle process termination
process.on('SIGINT', () => {
    console.log(chalk.yellow('\n\n👋 Shutting down dashboard...'));
    serverProcess.kill();
    process.exit(0);
});

process.on('SIGTERM', () => {
    serverProcess.kill();
    process.exit(0);
});

// Keep the process running
process.stdin.resume();

console.log(chalk.dim('\nPress Ctrl+C to stop the dashboard\n'));

