#!/usr/bin/env node

/**
 * Backend service for the Artwork Manager GUI
 * Handles file operations and integrates with existing scripts
 */

import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs/promises';
import { fileURLToPath } from 'url';
import sharp from 'sharp';
import { spawn } from 'child_process';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = 3001;

// Configure multer for file uploads
const upload = multer({ 
    dest: '/tmp/artwork-uploads/',
    limits: { 
        fileSize: 100 * 1024 * 1024, // 100MB limit
        fieldSize: 100 * 1024 * 1024  // 100MB field limit
    }
});

app.use(express.json({ limit: '100mb' }));
app.use(express.urlencoded({ limit: '100mb', extended: true }));
app.use(express.static(__dirname));

// CORS for development
app.use((req, res, next) => {
    res.header('Access-Control-Allow-Origin', '*');
    res.header('Access-Control-Allow-Headers', 'Origin, X-Requested-With, Content-Type, Accept');
    res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
    next();
});

class ArtworkManagerBackend {
    constructor() {
        this.artworksJsonPath = path.join(__dirname, '../src/data/artworks.json');
        this.imagesBasePath = path.join(__dirname, '../src/images/artworks');
    }

    async readArtworksJson() {
        try {
            const data = await fs.readFile(this.artworksJsonPath, 'utf8');
            return JSON.parse(data);
        } catch (error) {
            console.error('Error reading artworks.json:', error);
            return [];
        }
    }

    async writeArtworksJson(artworks) {
        await fs.writeFile(this.artworksJsonPath, JSON.stringify(artworks, null, 2));
    }

    async getNextId(artworks) {
        if (!artworks.length) return 1;
        return Math.max(...artworks.map(a => parseInt(a.id))) + 1;
    }

    async getCollectionSize(artworks, collection) {
        return artworks.filter(a => a.collection === collection).length;
    }

    generateSlug(title) {
        return title
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/^-+|-+$/g, '');
    }

    async processImage(sourcePath, targetDir, width, quality, filename) {
        await fs.mkdir(targetDir, { recursive: true });

        const outputPath = path.join(targetDir, filename);

        await sharp(sourcePath)
            .resize(width, null, { withoutEnlargement: true })
            .jpeg({ quality })
            .toFile(outputPath);

        return outputPath;
    }

    async enhanceMetadata(imagePath, title, collection = 'Unknown') {
        try {
            // Import OpenAI directly since the enhance-artwork-metadata.js expects relative paths
            const { OpenAI } = await import('openai');
            const sharp = (await import('sharp')).default;
            const dotenv = (await import('dotenv')).default;

            // Load environment variables
            dotenv.config({ path: path.join(__dirname, '../.env') });

            const openai = new OpenAI({
                apiKey: process.env.OPENAI_API_KEY,
            });

            // Read and encode the image directly from the temp path
            const buffer = await sharp(imagePath)
                .jpeg({ quality: 80 })
                .resize(1024, 1024, { fit: 'inside', withoutEnlargement: true })
                .toBuffer();

            const imageBase64 = buffer.toString('base64');

            const prompt = `Analyze this artwork titled "${title}" from the collection "${collection}".

Write like a knowledgeable gallery curator describing the work to collectors. Be matter-of-fact, sophisticated, and avoid commercial language.

Provide analysis in this JSON format:

{
  "description": "A single factual sentence describing what the viewer sees and experiences.",
  "style_tags": ["tag1", "tag2", "tag3"],
  "color_palette": ["color1", "color2", "color3"],
  "mood": "emotional character",
  "possible_locations": ["space1", "space2", "space3"],
  "tone_matches": ["style1", "style2", "style3"],
  "enhanced_description": "A thoughtful paragraph expanding on the visual elements and spatial relationships."
}

STRICT REQUIREMENTS:
- description: State what is observed, not what is "captivating" or "striking." No marketing adjectives like "captivating," "stunning," "mesmerizing," "bold," "vibrant," "dynamic."
- Absolutely NO mention of: digital, technique, medium, artistic process, creation method
- NO commercial language: "would appeal to," "perfect for," "ideal for," "enhances," "adds to"
- Use precise color names: "vermillion" not "red," "charcoal" not "black," "ivory" not "white"
- mood: 1-2 words only (e.g., "contemplative," "kinetic energy," "serene tension")
- enhanced_description: Expand on visual relationships, composition, color interaction. Describe what the work does spatially and visually, not what it "offers" or "provides"

Write as if documenting the work for a museum catalog - factual, observant, sophisticated. Focus on formal elements: line, form, color, space, rhythm, balance.`;

            const response = await openai.chat.completions.create({
                model: "gpt-4o",
                messages: [
                    {
                        role: "user",
                        content: [
                            { type: "text", text: prompt },
                            {
                                type: "image_url",
                                image_url: {
                                    url: `data:image/jpeg;base64,${imageBase64}`,
                                    detail: "high"
                                }
                            }
                        ]
                    }
                ],
                max_tokens: 1000,
                temperature: 0.7,
            });

            const content = response.choices[0].message.content;

            // Extract JSON from response
            const jsonMatch = content.match(/\{[\s\S]*\}/);
            if (!jsonMatch) {
                throw new Error('No JSON found in response');
            }

            const analysis = JSON.parse(jsonMatch[0]);

            return {
                description: analysis.description,
                enhancedDescription: analysis.enhanced_description,
                styleTags: analysis.style_tags,
                colorPalette: analysis.color_palette,
                mood: analysis.mood,
                possibleLocations: analysis.possible_locations,
                toneMatches: analysis.tone_matches
            };
        } catch (error) {
            console.error('AI enhancement failed, using fallback:', error);
            // Fallback to a less cheesy description
            return {
                description: `${title} - An artwork exploring form, color, and composition.`,
                enhancedDescription: `This piece presents a visual study of color relationships and spatial elements within the ${collection} collection.`,
                styleTags: ['contemporary', 'abstract'],
                colorPalette: ['varied'],
                mood: 'contemplative',
                possibleLocations: ['gallery space', 'private collection'],
                toneMatches: ['modern', 'artistic']
            };
        }
    }

    createArtworkEntry(id, formData, imagePath, collectionSize) {
        const folderPath = formData.collection.toLowerCase().replace(/\s+/g, '_');
        const collectionNumber = collectionSize + 1;

        const imageDir = collectionSize > 0 ? `${folderPath}/_${collectionNumber}` : folderPath;
        const imageSrc = `images/artworks/${imageDir}/mediumres.jpg`;

        return {
            id: id.toString(),
            src: imageSrc,
            alt: formData.title,
            title: formData.title,
            basePrice: formData.basePrice,
            collection: formData.collection,
            isFeatured: false,
            seriesSize: 100,
            description: formData.description,
            additionalInfo: formData.enhancedDescription,
            collectionSize: collectionSize + 1,
            aspectRatio: formData.aspectRatio || '1:1',
            power: 1,
            enhanced_description: formData.enhancedDescription,
            style_tags: formData.styleTags,
            color_palette: formData.colorPalette,
            mood: formData.mood,
            possible_locations: formData.possibleLocations,
            tone_matches: formData.toneMatches
        };
    }

    async updateCLIPSimilarity(artworkId) {
        const scriptPath = path.join(__dirname, 'update-clip-similarity.py');
        const pythonPath = path.join(__dirname, 'clip-venv/bin/python');
        const artworksJsonPath = path.join(__dirname, '../public/data/artworks.json');
        const imagesPath = path.join(__dirname, '../public');
        const embeddingsPath = path.join(__dirname, '../public/data/clip_embeddings.json');
        const similarityPath = path.join(__dirname, '../public/data/artwork_similarity.json');

        return new Promise((resolve, reject) => {
            const pythonProcess = spawn(pythonPath, [
                scriptPath,
                '--artwork-id', artworkId.toString(),
                '--artworks-json', artworksJsonPath,
                '--images-path', imagesPath,
                '--embeddings-file', embeddingsPath,
                '--similarity-file', similarityPath,
                '--model', 'ViT-B/32'
            ], {
                stdio: ['pipe', 'pipe', 'pipe']
            });

            let stdout = '';
            let stderr = '';

            pythonProcess.stdout.on('data', (data) => {
                stdout += data.toString();
                console.log('[CLIP Update]', data.toString().trim());
            });

            pythonProcess.stderr.on('data', (data) => {
                stderr += data.toString();
                console.error('[CLIP Error]', data.toString().trim());
            });

            pythonProcess.on('close', (code) => {
                if (code === 0) {
                    resolve(stdout);
                } else {
                    reject(new Error(`CLIP update failed with code ${code}: ${stderr}`));
                }
            });

            pythonProcess.on('error', (error) => {
                reject(new Error(`Failed to start CLIP update process: ${error.message}`));
            });
        });
    }
}

const backend = new ArtworkManagerBackend();

// Routes
app.get('/api/collections', async (req, res) => {
    try {
        const artworks = await backend.readArtworksJson();
        const collections = [...new Set(artworks.map(a => a.collection))].sort();
        res.json(collections);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

app.post('/api/enhance-metadata', upload.single('image'), async (req, res) => {
    try {
        const { title, collection } = req.body;
        const imagePath = req.file.path;

        console.log(`Enhancing metadata for: ${title} (${collection || 'Unknown'})`);

        const metadata = await backend.enhanceMetadata(imagePath, title, collection);

        // Clean up uploaded file
        await fs.unlink(imagePath);

        res.json(metadata);
    } catch (error) {
        console.error('Error enhancing metadata:', error);
        res.status(500).json({ error: error.message });
    }
});

app.post('/api/save-artwork', upload.single('image'), async (req, res) => {
    try {
        const formData = JSON.parse(req.body.formData);
        const imagePath = req.file.path;

        console.log('Saving artwork:', formData.title);

        // Read existing artworks
        const artworks = await backend.readArtworksJson();

        // Calculate new artwork details
        const newId = await backend.getNextId(artworks);
        const existingCollectionSize = await backend.getCollectionSize(artworks, formData.collection);
        const collectionNumber = existingCollectionSize + 1;

        // Create target directory
        const folderPath = formData.collection.toLowerCase().replace(/\s+/g, '_');
        const targetSubDir = existingCollectionSize > 0 ? `_${collectionNumber}` : '';
        const targetDir = path.join(backend.imagesBasePath, folderPath, targetSubDir);

        // Process images at different resolutions
        await backend.processImage(imagePath, targetDir, 400, 60, 'lowres.jpg');
        await backend.processImage(imagePath, targetDir, 800, 80, 'mediumres.jpg');

        // Create artwork entry
        const newArtwork = backend.createArtworkEntry(newId, formData, imagePath, existingCollectionSize);

        // Add to artworks and save
        artworks.push(newArtwork);
        await backend.writeArtworksJson(artworks);

        // Clean up uploaded file
        await fs.unlink(imagePath);

        console.log(`✓ Artwork "${formData.title}" saved with ID ${newId}`);

        // Update CLIP similarity matrix for the new artwork
        try {
            console.log('Updating CLIP similarity for new artwork...');
            await backend.updateCLIPSimilarity(newId);
            console.log('✓ CLIP similarity updated successfully');
        } catch (error) {
            console.warn('⚠️ CLIP similarity update failed (artwork still saved):', error.message);
        }

        res.json({ 
            success: true, 
            id: newId,
            message: `Artwork "${formData.title}" saved successfully! CLIP similarity updated.`
        });

    } catch (error) {
        console.error('Error saving artwork:', error);
        res.status(500).json({ error: error.message });
    }
});

// Start server
app.listen(port, () => {
    console.log(`🎨 Artwork Manager Backend running at http://localhost:${port}`);
    console.log(`📝 Open http://localhost:${port}/artwork-manager.html to use the GUI`);
});

export default app;

