// Dashboard JavaScript
let artworks = [];
let selectedArtworks = new Set();
let currentEditId = null;

// Initialize dashboard
document.addEventListener('DOMContentLoaded', () => {
    loadArtworks();
    setupEventListeners();
    updateStats();
});

// Setup event listeners
function setupEventListeners() {
    // Tab switching
    document.querySelectorAll('.tabs li').forEach(tab => {
        tab.addEventListener('click', (e) => {
            const tabName = e.currentTarget.dataset.tab;
            switchTab(tabName);
        });
    });

    // Search functionality
    const searchInput = document.getElementById('search-input');
    if (searchInput) {
        searchInput.addEventListener('input', (e) => {
            filterArtworks(e.target.value);
        });
    }

    // Sort functionality
    const sortSelect = document.getElementById('sort-select');
    if (sortSelect) {
        sortSelect.addEventListener('change', (e) => {
            sortArtworks(e.target.value);
        });
    }

    // Add artwork form
    const addForm = document.getElementById('add-artwork-form');
    if (addForm) {
        addForm.addEventListener('submit', handleAddArtwork);
    }
}

// Switch tabs
function switchTab(tabName) {
    // Update tab UI
    document.querySelectorAll('.tabs li').forEach(li => li.classList.remove('is-active'));
    document.querySelector(`[data-tab="${tabName}"]`).classList.add('is-active');

    // Hide all tab contents
    document.querySelectorAll('.tab-content').forEach(content => {
        content.style.display = 'none';
    });

    // Show selected tab
    document.getElementById(`${tabName}-tab`).style.display = 'block';

    // Load content if needed
    if (tabName === 'artworks') {
        renderArtworks();
    } else if (tabName === 'bulk-edit') {
        renderBulkEditGrid();
    }
}

// Load artworks from server
async function loadArtworks() {
    try {
        const response = await fetch('/api/artworks');
        artworks = await response.json();
        updateStats();
        renderArtworks();
    } catch (error) {
        console.error('Error loading artworks:', error);
        showMessage('Failed to load artworks', 'error');
    }
}

// Update statistics
function updateStats() {
    document.getElementById('total-artworks').textContent = artworks.length;

    const collections = new Set(artworks.map(a => a.collection));
    document.getElementById('total-collections').textContent = collections.size;

    const featured = artworks.filter(a => a.isFeatured).length;
    document.getElementById('featured-count').textContent = featured;

    const avgPrice = artworks.reduce((sum, a) => sum + (a.basePrice || 0), 0) / artworks.length;
    document.getElementById('avg-price').textContent = `$${Math.round(avgPrice)}`;
}

// Render artworks grid
function renderArtworks() {
    const grid = document.getElementById('artwork-grid');
    if (!grid) return;

    grid.innerHTML = artworks.map(artwork => `
        <div class="artwork-card" onclick="editArtwork('${artwork.id}')">
            <img src="../public/${artwork.src}" alt="${artwork.alt}" class="artwork-image" 
                 onerror="this.src='https://via.placeholder.com/250x200?text=No+Image'">
            <div class="artwork-info">
                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="has-text-grey">${artwork.collection}</p>
                <p class="artwork-price">$${artwork.basePrice}</p>
                ${artwork.isFeatured ? '<span class="tag is-warning">Featured</span>' : ''}
            </div>
        </div>
    `).join('');
}

// Render bulk edit grid
function renderBulkEditGrid() {
    const grid = document.getElementById('bulk-artwork-grid');
    if (!grid) return;

    grid.innerHTML = artworks.map(artwork => `
        <div class="artwork-card">
            <div class="checkbox-wrapper">
                <input type="checkbox" id="bulk-${artwork.id}" 
                       onchange="toggleSelection('${artwork.id}')"
                       ${selectedArtworks.has(artwork.id) ? 'checked' : ''}>
            </div>
            <img src="../public/${artwork.src}" alt="${artwork.alt}" class="artwork-image"
                 onerror="this.src='https://via.placeholder.com/250x200?text=No+Image'">
            <div class="artwork-info">
                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="artwork-price">$${artwork.basePrice}</p>
            </div>
        </div>
    `).join('');

    updateSelectedCount();
}

// Filter artworks
function filterArtworks(query) {
    const filtered = artworks.filter(artwork => 
        artwork.title.toLowerCase().includes(query.toLowerCase()) ||
        artwork.collection.toLowerCase().includes(query.toLowerCase())
    );

    const grid = document.getElementById('artwork-grid');
    grid.innerHTML = filtered.map(artwork => `
        <div class="artwork-card" onclick="editArtwork('${artwork.id}')">
            <img src="../public/${artwork.src}" alt="${artwork.alt}" class="artwork-image"
                 onerror="this.src='https://via.placeholder.com/250x200?text=No+Image'">
            <div class="artwork-info">
                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="has-text-grey">${artwork.collection}</p>
                <p class="artwork-price">$${artwork.basePrice}</p>
            </div>
        </div>
    `).join('');
}

// Sort artworks
function sortArtworks(sortBy) {
    let sorted = [...artworks];

    switch(sortBy) {
        case 'title':
            sorted.sort((a, b) => a.title.localeCompare(b.title));
            break;
        case 'price':
            sorted.sort((a, b) => b.basePrice - a.basePrice);
            break;
        case 'collection':
            sorted.sort((a, b) => a.collection.localeCompare(b.collection));
            break;
        case 'featured':
            sorted.sort((a, b) => (b.isFeatured ? 1 : 0) - (a.isFeatured ? 1 : 0));
            break;
    }

    artworks = sorted;
    renderArtworks();
}

// Handle add artwork
async function handleAddArtwork(e) {
    e.preventDefault();

    const formData = new FormData(e.target);

    showLoading();

    try {
        const response = await fetch('/api/artworks', {
            method: 'POST',
            body: formData
        });

        if (response.ok) {
            showMessage('Artwork added successfully!', 'success');
            e.target.reset();
            loadArtworks();
            switchTab('artworks');
        } else {
            throw new Error('Failed to add artwork');
        }
    } catch (error) {
        showMessage('Error adding artwork: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Edit artwork
function editArtwork(id) {
    const artwork = artworks.find(a => a.id === id);
    if (!artwork) return;

    currentEditId = id;

    // Populate edit form
    const form = document.getElementById('edit-artwork-form');
    form.innerHTML = `
        <div class="field">
            <label class="label">Title</label>
            <div class="control">
                <input class="input" type="text" id="edit-title" value="${artwork.title}">
            </div>
        </div>

        <div class="field">
            <label class="label">Collection</label>
            <div class="control">
                <input class="input" type="text" id="edit-collection" value="${artwork.collection}">
            </div>
        </div>

        <div class="field">
            <label class="label">Base Price ($)</label>
            <div class="control">
                <input class="input" type="number" id="edit-price" value="${artwork.basePrice}">
            </div>
        </div>

        <div class="field">
            <label class="label">Description</label>
            <div class="control">
                <textarea class="textarea" id="edit-description" rows="3">${artwork.description || ''}</textarea>
            </div>
        </div>

        <div class="field">
            <label class="checkbox">
                <input type="checkbox" id="edit-featured" ${artwork.isFeatured ? 'checked' : ''}>
                Featured Artwork
            </label>
        </div>

        <div class="field is-grouped is-grouped-right">
            <div class="control">
                <button class="button is-danger" onclick="deleteArtwork('${id}')">
                    <i class="fas fa-trash"></i> Delete
                </button>
            </div>
        </div>
    `;

    // Show modal
    document.getElementById('edit-modal').classList.add('is-active');
}

// Save artwork changes
async function saveArtwork() {
    const artwork = {
        title: document.getElementById('edit-title').value,
        collection: document.getElementById('edit-collection').value,
        basePrice: parseInt(document.getElementById('edit-price').value),
        description: document.getElementById('edit-description').value,
        isFeatured: document.getElementById('edit-featured').checked
    };

    showLoading();

    try {
        const response = await fetch(`/api/artworks/${currentEditId}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(artwork)
        });

        if (response.ok) {
            showMessage('Artwork updated successfully!', 'success');
            closeEditModal();
            loadArtworks();
        } else {
            throw new Error('Failed to update artwork');
        }
    } catch (error) {
        showMessage('Error updating artwork: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Delete artwork
async function deleteArtwork(id) {
    if (!confirm('Are you sure you want to delete this artwork?')) return;

    showLoading();

