// Setup event listeners
function setupEventListeners() {
    // Tab switching
    document.querySelectorAll('.tabs li').forEach(tab => {
        tab.addEventListener('click', (e) => {
            const tabName = e.currentTarget.dataset.tab;
            switchTab(tabName);
        });
