// Switch tabs
function switchTab(tabName) {
    // Update tab UI
    document.querySelectorAll('.tabs li').forEach(li => li.classList.remove('is-active'));
    document.querySelector(`[data-tab="${tabName}"]`).classList.add('is-active');

    // Hide all tab contents
    document.querySelectorAll('.tab-content').forEach(content => {
        content.style.display = 'none';
    });

    // Show selected tab
    document.getElementById(`${tabName}-tab`).style.display = 'block';

    // Load content if needed
    if (tabName === 'artworks') {
        renderArtworks();
    } else if (tabName === 'bulk-edit') {
        renderBulkEditGrid();
    }
}

// Load artworks from server
async function loadArtworks() {
    try {
        const response = await fetch('/api/artworks');
        artworks = await response.json();
        updateStats();
        renderArtworks();
    } catch (error) {
        console.error('Error loading artworks:', error);
        showMessage('Failed to load artworks', 'error');
    }
}

// Update statistics
function updateStats() {
    document.getElementById('total-artworks').textContent = artworks.length;

    const collections = new Set(artworks.map(a => a.collection));
    document.getElementById('total-collections').textContent = collections.size;

    const featured = artworks.filter(a => a.isFeatured).length;
    document.getElementById('featured-count').textContent = featured;

    const avgPrice = artworks.reduce((sum, a) => sum + (a.basePrice || 0), 0) / artworks.length;
    document.getElementById('avg-price').textContent = `$${Math.round(avgPrice)}`;
}

// Render artworks grid
function renderArtworks() {
    const grid = document.getElementById('artwork-grid');
    if (!grid) return;

    grid.innerHTML = artworks.map(artwork => `
        <div class="artwork-card" onclick="editArtwork('${artwork.id}')">
            <img src="/${artwork.src}" alt="${artwork.alt}" class="artwork-image" 
                 onerror="this.onerror=null; this.src='data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%22250%22 height=%22200%22%3E%3Crect width=%22250%22 height=%22200%22 fill=%22%23333%22/%3E%3Ctext x=%2250%25%22 y=%2250%25%22 text-anchor=%22middle%22 dy=%22.3em%22 fill=%22%23666%22 font-family=%22Arial%22%3ENo Image%3C/text%3E%3C/svg%3E'">
