                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="has-text-grey">${artwork.collection}</p>
                <p class="artwork-price">$${artwork.basePrice}</p>
                ${artwork.isFeatured ? '<span class="tag is-warning">Featured</span>' : ''}
            </div>
        </div>
    `).join('');
}

// Render bulk edit grid
function renderBulkEditGrid() {
    const grid = document.getElementById('bulk-artwork-grid');
    if (!grid) return;

    grid.innerHTML = artworks.map(artwork => `
        <div class="artwork-card">
            <div class="checkbox-wrapper">
                <input type="checkbox" id="bulk-${artwork.id}" 
                       onchange="toggleSelection('${artwork.id}')"
                       ${selectedArtworks.has(artwork.id) ? 'checked' : ''}>
            </div>
            <img src="../public/${artwork.src}" alt="${artwork.alt}" class="artwork-image"
                 onerror="this.src='https://via.placeholder.com/250x200?text=No+Image'">
            <div class="artwork-info">
                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="artwork-price">$${artwork.basePrice}</p>
            </div>
        </div>
    `).join('');

    updateSelectedCount();
}

// Filter artworks
function filterArtworks(query) {
    const filtered = artworks.filter(artwork => 
        artwork.title.toLowerCase().includes(query.toLowerCase()) ||
        artwork.collection.toLowerCase().includes(query.toLowerCase())
    );

    const grid = document.getElementById('artwork-grid');
    grid.innerHTML = filtered.map(artwork => `
        <div class="artwork-card" onclick="editArtwork('${artwork.id}')">
            <img src="../public/${artwork.src}" alt="${artwork.alt}" class="artwork-image"
                 onerror="this.src='https://via.placeholder.com/250x200?text=No+Image'">
            <div class="artwork-info">
                <h4 class="artwork-title">${artwork.title}</h4>
                <p class="has-text-grey">${artwork.collection}</p>
                <p class="artwork-price">$${artwork.basePrice}</p>
            </div>
        </div>
    `).join('');
}

// Sort artworks
function sortArtworks(sortBy) {
    let sorted = [...artworks];

    switch(sortBy) {
        case 'title':
            sorted.sort((a, b) => a.title.localeCompare(b.title));
            break;
        case 'price':
            sorted.sort((a, b) => b.basePrice - a.basePrice);
            break;
        case 'collection':
            sorted.sort((a, b) => a.collection.localeCompare(b.collection));
            break;
        case 'featured':
            sorted.sort((a, b) => (b.isFeatured ? 1 : 0) - (a.isFeatured ? 1 : 0));
            break;
    }

    artworks = sorted;
    renderArtworks();
}

