    } finally {
        hideLoading();
    }
}

// Edit artwork
function editArtwork(id) {
    const artwork = artworks.find(a => a.id === id);
    if (!artwork) return;

    currentEditId = id;

    // Populate edit form
    const form = document.getElementById('edit-artwork-form');
    form.innerHTML = `
        <div class="field">
            <label class="label">Title</label>
            <div class="control">
                <input class="input" type="text" id="edit-title" value="${artwork.title}">
            </div>
        </div>

        <div class="field">
            <label class="label">Collection</label>
            <div class="control">
                <input class="input" type="text" id="edit-collection" value="${artwork.collection}">
            </div>
        </div>

        <div class="field">
            <label class="label">Base Price ($)</label>
            <div class="control">
                <input class="input" type="number" id="edit-price" value="${artwork.basePrice}">
            </div>
        </div>

        <div class="field">
            <label class="label">Description</label>
            <div class="control">
                <textarea class="textarea" id="edit-description" rows="3">${artwork.description || ''}</textarea>
            </div>
        </div>

        <div class="field">
            <label class="checkbox">
                <input type="checkbox" id="edit-featured" ${artwork.isFeatured ? 'checked' : ''}>
                Featured Artwork
            </label>
        </div>

        <div class="field is-grouped is-grouped-right">
            <div class="control">
                <button class="button is-danger" onclick="deleteArtwork('${id}')">
                    <i class="fas fa-trash"></i> Delete
                </button>
            </div>
        </div>
    `;

    // Show modal
    document.getElementById('edit-modal').classList.add('is-active');
}

// Save artwork changes
async function saveArtwork() {
    const artwork = {
        title: document.getElementById('edit-title').value,
        collection: document.getElementById('edit-collection').value,
        basePrice: parseInt(document.getElementById('edit-price').value),
        description: document.getElementById('edit-description').value,
        isFeatured: document.getElementById('edit-featured').checked
    };

    showLoading();

    try {
        const response = await fetch(`/api/artworks/${currentEditId}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(artwork)
        });

        if (response.ok) {
            showMessage('Artwork updated successfully!', 'success');
            closeEditModal();
            loadArtworks();
        } else {
            throw new Error('Failed to update artwork');
        }
    } catch (error) {
        showMessage('Error updating artwork: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Delete artwork
async function deleteArtwork(id) {
    if (!confirm('Are you sure you want to delete this artwork?')) return;

    showLoading();

    try {
        const response = await fetch(`/api/artworks/${id}`, {
            method: 'DELETE'
        });

        if (response.ok) {
            showMessage('Artwork deleted successfully!', 'success');
            closeEditModal();
            loadArtworks();
        } else {
            throw new Error('Failed to delete artwork');
        }
    } catch (error) {
        showMessage('Error deleting artwork: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Bulk operations
function toggleSelection(id) {
    if (selectedArtworks.has(id)) {
        selectedArtworks.delete(id);
    } else {
        selectedArtworks.add(id);
    }
    updateSelectedCount();
}

function selectAll() {
    artworks.forEach(a => selectedArtworks.add(a.id));
    renderBulkEditGrid();
}

function selectNone() {
    selectedArtworks.clear();
    renderBulkEditGrid();
}

function updateSelectedCount() {
    document.querySelector('.selected-count').textContent = `${selectedArtworks.size} selected`;
}

async function updateBulkPrice() {
    const newPrice = document.getElementById('bulk-price').value;
    if (!newPrice || selectedArtworks.size === 0) return;

    if (!confirm(`Update ${selectedArtworks.size} artworks to $${newPrice}?`)) return;

    showLoading();

    try {
        const response = await fetch('/api/artworks/bulk-update', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                ids: Array.from(selectedArtworks),
                updates: { basePrice: parseInt(newPrice) }
            })
        });

        if (response.ok) {
            showMessage('Prices updated successfully!', 'success');
            selectedArtworks.clear();
            loadArtworks();
        } else {
            throw new Error('Failed to update prices');
        }
    } catch (error) {
        showMessage('Error updating prices: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Build operations
async function buildSite() {
    if (!confirm('Build and deploy the site?')) return;

    showLoading();
    const outputDiv = document.getElementById('build-output');
    const preElement = outputDiv.querySelector('pre');
    outputDiv.style.display = 'block';
    preElement.textContent = 'Starting build...\n';

    try {
        const response = await fetch('/api/build', {
            method: 'POST'
        });

        const reader = response.body.getReader();
        const decoder = new TextDecoder();

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            const text = decoder.decode(value);
            preElement.textContent += text;
            preElement.scrollTop = preElement.scrollHeight;
        }

        showMessage('Build completed!', 'success');
        document.getElementById('last-build').textContent = new Date().toLocaleString();
    } catch (error) {
        showMessage('Build failed: ' + error.message, 'error');
    } finally {
        hideLoading();
    }
}

// Utility functions
function closeEditModal() {
    document.getElementById('edit-modal').classList.remove('is-active');
}

function showLoading() {
    document.getElementById('loading').classList.add('is-active');
}

function hideLoading() {
    document.getElementById('loading').classList.remove('is-active');
}

function showMessage(message, type) {
    const div = document.createElement('div');
    div.className = `status-message status-${type}`;
    div.textContent = message;

    document.querySelector('.main-container').insertBefore(div, document.querySelector('.tabs'));

    setTimeout(() => div.remove(), 5000);
}

// Export data
async function exportData() {
    const dataStr = JSON.stringify(artworks, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `artworks-backup-${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
}

// Placeholder functions for maintenance
async function buildDev() {
    alert('This would start the development server. Run "npm run dev" in terminal.');
}

async function regenerateImages() {
    alert('This would regenerate all artwork images.');
}

async function updateSitemap() {
    alert('This would update the sitemap.');
}

async function clearCache() {
    alert('This would clear the build cache.');
}

